#include <iostream>
#include <memory>

class Shape { public: virtual ~Shape() = default; virtual long long area() const = 0; };
class Square : public Shape { long long side_; public: explicit Square(long long side) : side_(side) {} long long area() const override { return side_ * side_; } };
class Rectangle : public Shape { long long width_, height_; public: Rectangle(long long width, long long height) : width_(width), height_(height) {} long long area() const override { return width_ * height_; } };

int main() {
    char kind{};
    if (!(std::cin >> kind)) return 1;
    std::unique_ptr<Shape> shape;
    if (kind == 's') { long long side{}; if (!(std::cin >> side)) return 1; shape = std::make_unique<Square>(side); }
    else if (kind == 'r') { long long width{}, height{}; if (!(std::cin >> width >> height)) return 1; shape = std::make_unique<Rectangle>(width, height); }
    else { std::cout << "invalid\n"; return 0; }
    std::cout << shape->area() << '\n';
}
